import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSettings(
  settings: Map[String, String],
  nestedSettings: Map[String, Map[String, String]]
)

class ConfigurationParserService {
  
  private val secureParserFactory: SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(true)
    factory
  }

  def parseConfiguration(xmlContent: String): Try[ConfigurationSettings] = {
    Try {
      val loader = new scala.xml.factory.XMLLoader[Elem] {
        override def parser = secureParserFactory.newSAXParser()
      }
      val xml = loader.load(new InputSource(new StringReader(xmlContent)))
      extractSettings(xml)
    }
  }

  def parseConfigurationUnsafe(xmlContent: String): Try[ConfigurationSettings] = {
    Try {
      val xml = XML.loadString(xmlContent)
      extractSettings(xml)
    }
  }

  private def extractSettings(xml: Elem): ConfigurationSettings = {
    val rootSettings = (xml \ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = (setting \ "@value").headOption.map(_.text).getOrElse(setting.text)
      key -> value
    }.toMap

    val nestedSettings = (xml \ "group").map { group =>
      val groupName = (group \ "@name").text
      val groupSettings = (group \ "setting").map { setting =>
        val key = (setting \ "@key").text
        val value = (setting \ "@value").headOption.map(_.text).getOrElse(setting.text)
        key -> value
      }.toMap
      groupName -> groupSettings
    }.toMap

    ConfigurationSettings(rootSettings, nestedSettings)
  }

  def getSetting(settings: ConfigurationSettings, key: String): Option[String] = {
    settings.settings.get(key)
  }

  def getNestedSetting(settings: ConfigurationSettings, group: String, key: String): Option[String] = {
    settings.nestedSettings.get(group).flatMap(_.get(key))
  }

  def getAllSettings(settings: ConfigurationSettings): Map[String, String] = {
    val nested = settings.nestedSettings.flatMap { case (group, groupSettings) =>
      groupSettings.map { case (key, value) =>
        s"$group.$key" -> value
      }
    }
    settings.settings ++ nested
  }

  def validateXml(xmlContent: String): Try[Boolean] = {
    parseConfiguration(xmlContent).map(_ => true)
  }

  def mergeConfigurations(configs: Seq[ConfigurationSettings]): ConfigurationSettings = {
    val mergedSettings = configs.flatMap(_.settings).toMap
    val mergedNested = configs.flatMap(_.nestedSettings).groupBy(_._1).map {
      case (group, groupMaps) =>
        group -> groupMaps.flatMap(_._2).toMap
    }
    ConfigurationSettings(mergedSettings, mergedNested)
  }
}

trait ConfigurationApi {
  val parserService: ConfigurationParserService

  def handleConfigurationRequest(xmlContent: String): Either[String, ConfigurationSettings] = {
    parserService.parseConfiguration(xmlContent) match {
      case Success(settings) => Right(settings)
      case Failure(exception) => Left(s"Failed to parse configuration: ${exception.getMessage}")
    }
  }

  def handleBatchConfigurationRequest(xmlContents: Seq[String]): Either[String, ConfigurationSettings] = {
    val results = xmlContents.map(parserService.parseConfiguration)
    
    if (results.forall(_.isSuccess)) {
      val configs = results.collect { case Success(config) => config }
      Right(parserService.mergeConfigurations(configs))
    } else {
      val errors = results.collect { case Failure(ex) => ex.getMessage }
      Left(s"Failed to parse configurations: ${errors.mkString(", ")}")
    }
  }

  def getSettingValue(xmlContent: String, key: String): Either[String, String] = {
    handleConfigurationRequest(xmlContent).flatMap { settings =>
      parserService.getSetting(settings, key)
        .toRight(s"Setting '$key' not found")
    }
  }

  def getNestedSettingValue(xmlContent: String, group: String, key: String): Either[String, String] = {
    handleConfigurationRequest(xmlContent).flatMap { settings =>
      parserService.getNestedSetting(settings, group, key)
        .toRight(s"Setting '$group.$key' not found")
    }
  }

  def getAllSettingsFlat(xmlContent: String): Either[String, Map[String, String]] = {
    handleConfigurationRequest(xmlContent).map { settings =>
      parserService.getAllSettings(settings)
    }
  }
}

class ConfigurationManagementSystem extends ConfigurationApi {
  override val parserService: ConfigurationParserService = new ConfigurationParserService()

  def processApiRequest(xmlPayload: String): Map[String, Any] = {
    handleConfigurationRequest(xmlPayload) match {
      case Right(settings) =>
        Map(
          "status" -> "success",
          "settings" -> parserService.getAllSettings(settings),
          "groups" -> settings.nestedSettings.keys.toSeq
        )
      case Left(error) =>
        Map(
          "status" -> "error",
          "message" -> error
        )
    }
  }

  def extractSpecificSettings(xmlPayload: String, keys: Seq[String]): Map[String, Any] = {
    handleConfigurationRequest(xmlPayload) match {
      case Right(settings) =>
        val allSettings = parserService.getAllSettings(settings)
        val extracted = keys.flatMap { key =>
          allSettings.get(key).map(key -> _)
        }.toMap
        
        Map(
          "status" -> "success",
          "settings" -> extracted
        )
      case Left(error) =>
        Map(
          "status" -> "error",
          "message" -> error
        )
    }
  }

  def updateConfiguration(xmlPayload: String, updates: Map[String, String]): Either[String, String] = {
    handleConfigurationRequest(xmlPayload).map { settings =>
      val updatedSettings = settings.settings ++ updates
      val newConfig = settings.copy(settings = updatedSettings)
      generateXml(newConfig)
    }
  }

  private def generateXml(settings: ConfigurationSettings): String = {
    val settingsXml = settings.settings.map { case (key, value) =>
      s"""<setting key="$key" value="$value"/>"""
    }.mkString("\n    ")

    val groupsXml = settings.nestedSettings.map { case (groupName, groupSettings) =>
      val groupSettingsXml = groupSettings.map { case (key, value) =>
        s"""<setting key="$key" value="$value"/>"""
      }.mkString("\n      ")
      s"""<group name="$groupName">
      $groupSettingsXml
    </group>"""
    }.mkString("\n    ")

    s"""<?xml version="1.0" encoding="UTF-8"?>
<configuration>
    $settingsXml
    $groupsXml
</configuration>"""
  }
}

object ConfigurationManagementApp {
  def main(args: Array[String]): Unit = {
    val system = new ConfigurationManagementSystem()
    
    val sampleXml = """<?xml version="1.0" encoding="UTF-8"?>
<configuration>
    <setting key="app.name" value="MyApp"/>
    <setting key="app.version" value="1.0.0"/>
    <group name="database">
        <setting key="host" value="localhost"/>
        <setting key="port" value="5432"/>
    </group>
    <group name="cache">
        <setting key="enabled" value="true"/>
        <setting key="ttl" value="3600"/>
    </group>
</configuration>"""

    val result = system.processApiRequest(sampleXml)
    println(s"Processing result: $result")

    val specificSettings = system.extractSpecificSettings(sampleXml, Seq("app.name", "database.host"))
    println(s"Specific settings: $specificSettings")
  }
